import React, { useEffect, useState, useMemo } from 'react';
import { Link } from 'react-router-dom';
import {
  ResponsiveContainer,
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  BarChart,
  Bar
} from 'recharts';
import {
  PoundSterling,
  ShoppingCart,
  Package,
  Users,
  TrendingUp,
  TrendingDown
} from 'lucide-react';
import { adminAPI } from '../../api/axios';
import { apiMessage } from '../../lib/api';
import { productImageUrl } from '../../lib/productImage';
import LoadingSpinner from '../../components/LoadingSpinner';

function formatGbp(n) {
  const v = Number(n) || 0;
  return `£${v.toLocaleString('en-GB', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
}

function formatMonthPoint(key) {
  if (!key || !/^\d{4}-\d{2}$/.test(key)) return key;
  const [y, m] = key.split('-');
  return new Date(Number(y), Number(m) - 1, 1).toLocaleString('en-GB', {
    month: 'short',
    year: '2-digit'
  });
}

function formatDayLabel(key) {
  if (!key) return '';
  const d = new Date(key + 'T12:00:00Z');
  return d.toLocaleDateString('en-GB', { day: 'numeric', month: 'short' });
}

function orderShortId(order) {
  if (!order?._id) return '—';
  return String(order._id).slice(-8).toUpperCase();
}

function statusClass(status) {
  return `admin-dash-badge admin-dash-badge--${status || 'pending'}`;
}

function Delta({ percentChange }) {
  if (percentChange == null || Number.isNaN(Number(percentChange))) {
    return <span className="admin-stat-card__delta admin-stat-card__delta--neutral">—</span>;
  }
  const n = Number(percentChange);
  const up = n >= 0;
  return (
    <span
      className={`admin-stat-card__delta ${up ? 'admin-stat-card__delta--up' : 'admin-stat-card__delta--down'}`}
    >
      {up ? <TrendingUp size={14} aria-hidden /> : <TrendingDown size={14} aria-hidden />}
      {up ? '+' : ''}
      {n.toFixed(1)}%
      <span className="admin-stat-card__delta-hint"> vs prior period</span>
    </span>
  );
}

function StatCard({ title, value, displayValue, percentChange, icon: Icon }) {
  return (
    <div className="admin-stat-card">
      <div className="admin-stat-card__top">
        <span className="admin-stat-card__icon" aria-hidden>
          <Icon size={22} strokeWidth={1.75} />
        </span>
        <span className="admin-stat-card__title">{title}</span>
      </div>
      <div className="admin-stat-card__value">{displayValue != null ? displayValue : value}</div>
      <Delta percentChange={percentChange} />
    </div>
  );
}

export default function AdminDashboard() {
  const [stats, setStats] = useState(null);
  const [revenuePoints, setRevenuePoints] = useState([]);
  const [orderPoints, setOrderPoints] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    let cancelled = false;
    (async () => {
      setLoading(true);
      setError(null);
      try {
        const [sRes, rRes, oRes] = await Promise.all([
          adminAPI.dashboard.stats(),
          adminAPI.dashboard.revenueChart({ period: '6m' }),
          adminAPI.dashboard.ordersChart()
        ]);
        if (cancelled) return;
        setStats(sRes.data?.data || null);
        setRevenuePoints(rRes.data?.data?.points || []);
        setOrderPoints(oRes.data?.data?.points || []);
      } catch (e) {
        if (!cancelled) {
          setError(apiMessage(e, 'Could not load dashboard'));
          setStats(null);
        }
      } finally {
        if (!cancelled) setLoading(false);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, []);

  const lineData = useMemo(
    () =>
      revenuePoints.map((p) => ({
        ...p,
        shortLabel: formatMonthPoint(p.key)
      })),
    [revenuePoints]
  );

  const barData = useMemo(
    () =>
      orderPoints.map((p) => ({
        ...p,
        shortLabel: formatDayLabel(p.key)
      })),
    [orderPoints]
  );

  const topRows = stats?.topProducts || [];
  const recent = stats?.recentOrders || [];
  const lowStock = stats?.lowStockList || [];

  if (loading) {
    return (
      <div className="admin-dashboard admin-dashboard--loading">
        <LoadingSpinner size="lg" label="Loading dashboard" />
      </div>
    );
  }

  if (error) {
    return (
      <div className="admin-dashboard">
        <p className="admin-dashboard__error">{error}</p>
      </div>
    );
  }

  return (
    <div className="admin-dashboard">
      <Helmet>
        <title>Admin dashboard | Nova Shop</title>
      </Helmet>
      <h1 className="admin-dashboard__title">Dashboard</h1>
      <p className="admin-dashboard__lede">Overview of store performance and activity.</p>

      <div className="admin-stat-grid">
        <StatCard
          title="Revenue (delivered, MTD)"
          value={stats?.totalRevenue?.value}
          displayValue={formatGbp(stats?.totalRevenue?.value)}
          percentChange={stats?.totalRevenue?.percentChange}
          icon={PoundSterling}
        />
        <StatCard
          title="Orders (MTD)"
          value={stats?.ordersMtd?.value}
          displayValue={stats?.ordersMtd?.value}
          percentChange={stats?.ordersMtd?.percentChange}
          icon={ShoppingCart}
        />
        <StatCard
          title="Products (catalog)"
          value={stats?.totalProducts?.value}
          displayValue={stats?.totalProducts?.value}
          percentChange={stats?.totalProducts?.percentChange}
          icon={Package}
        />
        <StatCard
          title="Customers"
          value={stats?.totalCustomers?.value}
          displayValue={stats?.totalCustomers?.value}
          percentChange={stats?.totalCustomers?.percentChange}
          icon={Users}
        />
      </div>

      <div className="admin-charts">
        <div className="admin-chart-card">
          <h2 className="admin-chart-card__title">Revenue (last 6 months)</h2>
          <p className="admin-chart-card__hint">Delivered orders by revenue recognition date (UTC months).</p>
          <div className="admin-chart-card__plot">
            <ResponsiveContainer width="100%" height={300}>
              <LineChart data={lineData} margin={{ top: 8, right: 8, left: 0, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="#2a2a3e" />
                <XAxis
                  dataKey="shortLabel"
                  tick={{ fill: '#9ca3af', fontSize: 11 }}
                  tickLine={false}
                  axisLine={{ stroke: '#2a2a3e' }}
                />
                <YAxis
                  tick={{ fill: '#9ca3af', fontSize: 11 }}
                  tickLine={false}
                  axisLine={{ stroke: '#2a2a3e' }}
                  tickFormatter={(v) => `£${Number(v) >= 1000 ? (v / 1000).toFixed(0) + 'k' : v}`}
                />
                <Tooltip
                  contentStyle={{
                    background: '#1a1a2e',
                    border: '1px solid #2a2a3e',
                    borderRadius: 8
                  }}
                  labelStyle={{ color: '#e5e7eb' }}
                  formatter={(val) => [formatGbp(val), 'Revenue']}
                />
                <Line
                  type="monotone"
                  dataKey="revenue"
                  stroke="#c8a84b"
                  strokeWidth={2}
                  dot={{ fill: '#c8a84b', r: 3 }}
                  activeDot={{ r: 5 }}
                />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>
        <div className="admin-chart-card">
          <h2 className="admin-chart-card__title">Orders (last 30 days)</h2>
          <p className="admin-chart-card__hint">All orders by created date (UTC days).</p>
          <div className="admin-chart-card__plot">
            <ResponsiveContainer width="100%" height={300}>
              <BarChart data={barData} margin={{ top: 8, right: 8, left: 0, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="#2a2a3e" />
                <XAxis
                  dataKey="shortLabel"
                  tick={{ fill: '#9ca3af', fontSize: 9 }}
                  tickLine={false}
                  axisLine={{ stroke: '#2a2a3e' }}
                  interval="preserveStartEnd"
                  minTickGap={8}
                />
                <YAxis
                  allowDecimals={false}
                  tick={{ fill: '#9ca3af', fontSize: 11 }}
                  tickLine={false}
                  axisLine={{ stroke: '#2a2a3e' }}
                />
                <Tooltip
                  contentStyle={{
                    background: '#1a1a2e',
                    border: '1px solid #2a2a3e',
                    borderRadius: 8
                  }}
                  labelStyle={{ color: '#e5e7eb' }}
                />
                <Bar dataKey="count" fill="#3d4f7c" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      <div className="admin-dash-tables">
        <section className="admin-dash-section">
          <h2 className="admin-dash-section__title">Recent orders</h2>
          <div className="admin-table-wrap">
            <table className="admin-table">
              <thead>
                <tr>
                  <th>Order</th>
                  <th>Customer</th>
                  <th>Amount</th>
                  <th>Status</th>
                  <th>Date</th>
                </tr>
              </thead>
              <tbody>
                {recent.length === 0 ? (
                  <tr>
                    <td colSpan={5} className="admin-table__empty">
                      No recent orders
                    </td>
                  </tr>
                ) : (
                  recent.map((o) => {
                    const cust = o.user?.name || o.user?.email || '—';
                    return (
                      <tr key={o._id}>
                        <td>
                          <Link to={`/admin/orders/${o._id}`} className="admin-table__link">
                            #{orderShortId(o)}
                          </Link>
                        </td>
                        <td>{cust}</td>
                        <td>{formatGbp(o.totalPrice)}</td>
                        <td>
                          <span className={statusClass(o.status)}>{o.status}</span>
                        </td>
                        <td>
                          {o.createdAt
                            ? new Date(o.createdAt).toLocaleString('en-GB', {
                                day: 'numeric',
                                month: 'short',
                                year: 'numeric',
                                hour: '2-digit',
                                minute: '2-digit'
                              })
                            : '—'}
                        </td>
                      </tr>
                    );
                  })
                )}
              </tbody>
            </table>
          </div>
        </section>

        <section className="admin-dash-section">
          <h2 className="admin-dash-section__title">Top products (30 days)</h2>
          <p className="admin-dash-section__hint">By revenue from non-cancelled orders.</p>
          <div className="admin-table-wrap">
            <table className="admin-table">
              <thead>
                <tr>
                  <th>Product</th>
                  <th>Units</th>
                  <th>Revenue</th>
                </tr>
              </thead>
              <tbody>
                {topRows.length === 0 ? (
                  <tr>
                    <td colSpan={3} className="admin-table__empty">
                      No data yet
                    </td>
                  </tr>
                ) : (
                  topRows.map((row, i) => {
                    const p = row.product;
                    const img = p ? productImageUrl(p) : '';
                    const name = p?.name || 'Product';
                    const link = p?.slug ? `/shop/${p.slug}` : null;
                    return (
                      <tr key={p?._id || i}>
                        <td>
                          <div className="admin-product-cell">
                            <div className="admin-product-cell__img">
                              {img ? (
                                <img src={img} alt="" />
                              ) : (
                                <span aria-hidden>·</span>
                              )}
                            </div>
                            <div>
                              {link ? (
                                <a href={link} className="admin-table__link" target="_blank" rel="noreferrer">
                                  {name}
                                </a>
                              ) : (
                                name
                              )}
                            </div>
                          </div>
                        </td>
                        <td>{row.units != null ? row.units : '—'}</td>
                        <td>{formatGbp(row.revenue)}</td>
                      </tr>
                    );
                  })
                )}
              </tbody>
            </table>
          </div>
        </section>
      </div>

      <section className="admin-dash-section admin-low-stock">
        <div className="admin-low-stock__head">
          <h2 className="admin-dash-section__title">Low stock alert</h2>
          <span className="admin-low-stock__badge">Stock &lt; 10</span>
        </div>
        {lowStock.length === 0 ? (
          <p className="admin-dashboard__lede">No products below threshold.</p>
        ) : (
          <ul className="admin-low-stock__list">
            {lowStock.map((p) => (
              <li key={p._id} className="admin-low-stock__row">
                <div className="admin-product-cell">
                  <div className="admin-product-cell__img">
                    {productImageUrl(p) ? (
                      <img src={productImageUrl(p)} alt="" />
                    ) : (
                      <span aria-hidden>·</span>
                    )}
                  </div>
                  <div>
                    <strong>{p.name}</strong>
                    <span className="admin-low-stock__meta">
                      Stock: <b>{p.stock}</b>
                    </span>
                  </div>
                </div>
                <Link
                  to={`/admin/products/${p._id}/edit`}
                  className="btn btn-sm admin-low-stock__btn"
                >
                  Restock
                </Link>
              </li>
            ))}
          </ul>
        )}
      </section>
    </div>
  );
}
